var item = $input.first().json;
var data = item.output || '';

var start = data.indexOf('{');
var end = data.lastIndexOf('}');

if (start === -1 || end === -1) {
  return [{ json: {
    error: 'No JSON found in agent output',
    raw_snippet: data.substring(0, 500),
    generated_at: new Date().toISOString()
  }}];
}

try {
  var parsed = JSON.parse(data.substring(start, end + 1));
  if (!parsed.generated_at) parsed.generated_at = new Date().toISOString();
  var defaults = {
    target: 'Unknown', who_are_they: '', who_leads_them: [],
    how_much_spend: {}, who_buying_from: [], how_they_buy: {},
    where_they_spend: {}, what_vehicles: [], what_they_buy: {},
    set_asides: {}, big_contracts: [], mid_contracts: [], eis_opportunities: {}
  };
  for (var k in defaults) { if (!parsed[k]) parsed[k] = defaults[k]; }
  return [{ json: parsed }];
} catch(e) {
  return [{ json: {
    error: 'JSON parse failed: ' + e.message,
    raw_snippet: data.substring(0, 500),
    generated_at: new Date().toISOString()
  }}];
}

const data = $input.first()?.json || {};
const target = ($('Webhook').first()?.json?.body?.agency || $('Webhook').first()?.json?.agency || 'unknown').toLowerCase();
// Upsert into gda_competitor_cache via a postgres exec
return [{ json: {
  target: target,
  timestamp: new Date().toISOString(),
  full_11q_result: JSON.stringify(data)
}}];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const rows = $input.all().map(i => i.json);
const competitors = rows.map(r => {
  let data = r.full_11q_result || {};
  if (typeof data === 'string') { try { data = JSON.parse(data); } catch(e) { data = {}; } }
  return {
    target: r.target,
    threat_level: data.threat_level || 'MEDIUM',
    strengths: data.strengths || [],
    weaknesses: data.weaknesses || [],
    overlap_with_gda: data.overlap_with_gda || '',
    watch_programs: data.watch_programs || [],
    key_vehicles: data.key_vehicles || [],
    revenue: data.revenue || '',
    hq: data.hq || '',
    created_at: r.created_at
  };
});
const order = { 'HIGH': 0, 'VERY HIGH': 0, 'MEDIUM': 1, 'LOW-MEDIUM': 1, 'LOW': 2, 'LOW (teaming target)': 2 };
competitors.sort((a, b) => (order[a.threat_level] || 1) - (order[b.threat_level] || 1));
return [{ json: { competitors, count: competitors.length } }];

const resp = $input.first().json;
let output = '';
if (resp.content && Array.isArray(resp.content)) {
  output = resp.content.map(c => c.text || '').join('');
} else if (resp.error) {
  output = JSON.stringify({error: resp.error.message || 'Anthropic API error', generated_at: new Date().toISOString()});
} else {
  output = JSON.stringify(resp);
}
return [{json: {output}}];
